content.query:
// Total Non-Human Identities
let SPs = AADServicePrincipalSignInLogs | where TimeGenerated >= ago(30d) | summarize by ServicePrincipalId | count | project Count;
let MIs = AADManagedIdentitySignInLogs | where TimeGenerated >= ago(30d) | summarize by ServicePrincipalId | count | project Count;
union SPs, MIs
| summarize TotalIdentities = sum(Count)
| project Metric = 'Monitored Identities', Value = TotalIdentities, Status = '📊'

// Week-over-Week Failure Change
let ThisWeek = AADServicePrincipalSignInLogs | where TimeGenerated >= ago(7d) | summarize TW = countif(ResultType != '0');
let LastWeek = AADServicePrincipalSignInLogs | where TimeGenerated between (ago(14d) .. ago(7d)) | summarize LW = countif(ResultType != '0');
ThisWeek | extend p = 1 | join kind=leftouter (LastWeek | extend p = 1) on p
| extend LW = coalesce(LW, 1)
| extend Change = round((todouble(TW) - LW) / LW * 100, 0)
| extend Status = case(Change > 50, strcat('🔴 +', tostring(toint(Change)), '%'), Change > 10, strcat('🟠 +', tostring(toint(Change)), '%'), Change < -10, strcat('🟢 ', tostring(toint(Change)), '%'), '➡️ Stable')
| project Metric = 'WoW Failures', Value = TW, Status

// Service Principal Activity Timeline
AADServicePrincipalSignInLogs
| where TimeGenerated {TimeRange}
| extend Status = case(ResultType == "0", "Success", "Failed")
| summarize Count = count() by bin(TimeGenerated, 1h), Status
| render timechart

// Managed Identity Resource Distribution
AADManagedIdentitySignInLogs
| where TimeGenerated {TimeRange}
| summarize Count = count() by Category
| order by Count desc

// Managed Identity Activity Timeline
AADManagedIdentitySignInLogs
| where TimeGenerated {TimeRange}
| extend Status = case(ResultType == "0", "Success", "Failed")
| summarize Count = count() by bin(TimeGenerated, 1h), Status
| render timechart

// Detect Illicit Consent Grant Attack Patterns
AuditLogs
| where TimeGenerated {TimeRange}
| where OperationName == "Consent to application"
| extend ConsentUser = tostring(InitiatedBy.user.userPrincipalName)
| extend ConsentIP = tostring(InitiatedBy.user.ipAddress)
| extend AppName = tostring(TargetResources[0].displayName)
| extend AppId = tostring(TargetResources[0].id)
| extend Permissions = tostring(TargetResources[0].modifiedProperties)
// Detect suspicious patterns
| extend IsSuspicious = case(
    // Consent from risky IP
    ConsentIP has_any ("tor", "vpn"), true,
    // High-risk permissions
    Permissions has_any ("Mail.Read", "Mail.Send", "Files.ReadWrite.All", "full_access"), true,
    // Unknown publisher apps
    AppName has_any ("test", "demo", "oauth", "token"), true,
    false
)
| where IsSuspicious == true
| project TimeGenerated, ConsentUser, ConsentIP, AppName, AppId, Permissions, IsSuspicious
| order by TimeGenerated desc

// CA Blocks Timeline for Service Principals
AADServicePrincipalSignInLogs
| where TimeGenerated {TimeRange}
| where ConditionalAccessStatus == "failure" or ResultType in ("53000", "53001", "53002", "53003")
| summarize BlockedCount = count() by bin(TimeGenerated, 1h)
| render timechart

// User Geographic Distribution
let targetUser = '{SelectedForensicUser}';
SigninLogs
| where TimeGenerated {ForensicTimeRange}
| where UserPrincipalName =~ targetUser or UserId == targetUser
| extend Country = tostring(LocationDetails.countryOrRegion)
| extend City = tostring(LocationDetails.city)
| summarize Count = count() by Country, City
| order by Count desc

// SP Activity Timeline
let targetSP = '{SelectedForensicSP}';
AADServicePrincipalSignInLogs
| where TimeGenerated {ForensicTimeRange}
| where ServicePrincipalName =~ targetSP or ServicePrincipalId == targetSP
| summarize Success = countif(ResultType == '0'), Failed = countif(ResultType != '0') by bin(TimeGenerated, 1h)
| render timechart

// SP Resource Access
let targetSP = '{SelectedForensicSP}';
AADServicePrincipalSignInLogs
| where TimeGenerated {ForensicTimeRange}
| where ServicePrincipalName =~ targetSP or ServicePrincipalId == targetSP
| summarize AccessCount = count() by ResourceDisplayName
| order by AccessCount desc

// MI Activity Timeline
let targetMI = '{SelectedForensicMI}';
AADManagedIdentitySignInLogs
| where TimeGenerated {ForensicTimeRange}
| where ServicePrincipalName =~ targetMI or ServicePrincipalId == targetMI
| summarize Success = countif(ResultType == '0'), Failed = countif(ResultType != '0') by bin(TimeGenerated, 1h)
| render timechart

// MI Resource Access
let targetMI = '{SelectedForensicMI}';
AADManagedIdentitySignInLogs
| where TimeGenerated {ForensicTimeRange}
| where ServicePrincipalName =~ targetMI or ServicePrincipalId == targetMI
| summarize AccessCount = count() by ResourceDisplayName
| order by AccessCount desc

// Device Activity Timeline
let targetDevice = '{SelectedForensicDevice}';
SigninLogs
| where TimeGenerated {ForensicTimeRange}
| where DeviceDetail.deviceId == targetDevice or DeviceDetail.displayName =~ targetDevice
| summarize Success = countif(ResultType == '0'), Failed = countif(ResultType != '0'), HighRisk = countif(RiskLevelDuringSignIn == 'high') by bin(TimeGenerated, 1h)
| render timechart
